function problemMatchesTags(problem, normalizedTags) {
  if (!normalizedTags || normalizedTags.length === 0) {
    return true;
  }
  if (!problem.tags || !Array.isArray(problem.tags)) {
    return false;
  }
  const problemTagsLower = problem.tags.map(t => String(t).toLowerCase());
  return normalizedTags.some(tag => problemTagsLower.includes(tag));
}

